1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const LOYALTY_DISCOUNT_RATE = 0.2;
4	const LOYALTY_THRESHOLD_YEARS = 2;
5	const COMPONENT_BLOCK_OF_3_PRICE = 60;
6	const CURSE_SURCHARGE_RATE = 0.5;
7	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
8	const HIGH_ENCHANTMENT_THRESHOLD = 5;
9	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
10	
11	const BASE_PREMIUMS: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	type Item = { type: string; cursed?: boolean; enchantment?: number };
21	type QuoteStep = { type: "quote"; items: Item[] };
22	type Customer = { yearsWithMHPCO: number };
23	type Scenario = { customer?: Customer; steps: QuoteStep[] };
24	
25	function groupByType(items: Item[]): Map<string, Item[]> {
26	  const groups = new Map<string, Item[]>();
27	  for (const item of items) {
28	    const group = groups.get(item.type) ?? [];
29	    group.push(item);
30	    groups.set(item.type, group);
31	  }
32	  return groups;
33	}
34	
35	function isHighlyEnchanted(item: Item): boolean {
36	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
37	}
38	
39	function calculateItemPremium(item: Item): number {
40	  const itemBase = BASE_PREMIUMS[item.type];
41	  const curseSurcharge = item.cursed ? itemBase * CURSE_SURCHARGE_RATE : 0;
42	  const highEnchantmentSurcharge = isHighlyEnchanted(item)
43	    ? itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE
44	    : 0;
45	  return itemBase + curseSurcharge + highEnchantmentSurcharge;
46	}
47	
48	function calculateGroupPremium(type: string, group: Item[]): number {
49	  if (COMPONENT_TYPES.has(type) && group.length === 3) {
50	    return COMPONENT_BLOCK_OF_3_PRICE;
51	  }
52	  return group.reduce((sum, item) => sum + calculateItemPremium(item), 0);
53	}
54	
55	function calculateGroupBareBase(type: string, group: Item[]): number {
56	  if (COMPONENT_TYPES.has(type) && group.length === 3) {
57	    return COMPONENT_BLOCK_OF_3_PRICE;
58	  }
59	  return group.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
60	}
61	
62	function calculateBasePremium(items: Item[]): number {
63	  return Array.from(groupByType(items)).reduce(
64	    (total, [type, group]) => total + calculateGroupPremium(type, group),
65	    0,
66	  );
67	}
68	
69	function calculateBareBasePremium(items: Item[]): number {
70	  return Array.from(groupByType(items)).reduce(
71	    (total, [type, group]) => total + calculateGroupBareBase(type, group),
72	    0,
73	  );
74	}
75	
76	export function runScenario(scenario: unknown): { results: { premium: number }[] } {
77	  const { customer, steps } = scenario as Scenario;
78	  const items = steps[0].items;
79	  const basePremium = calculateBasePremium(items);
80	  const bareBasePremium = calculateBareBasePremium(items);
81	  const firstInsuranceSurcharge = bareBasePremium * FIRST_INSURANCE_RATE;
82	  const loyaltyDiscount =
83	    (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_THRESHOLD_YEARS
84	      ? bareBasePremium * LOYALTY_DISCOUNT_RATE
85	      : 0;
86	  const premium =
87	    basePremium - loyaltyDiscount + firstInsuranceSurcharge + PROCESSING_FEE;
88	  return { results: [{ premium }] };
89	}
